# Commit 32: Enhance train_models_direct.py: implement part 2 of core functionality
dest_path = os.path.join(TARGET_DIR, r'train_models_direct.py')
os.makedirs(os.path.dirname(dest_path), exist_ok=True)
with open(dest_path, 'a', encoding='utf-8') as f_out:
    f_out.write('def rmse_original(y_true_log, y_pred_log):\n    return np.sqrt(mean_squared_error(np.expm1(y_true_log),\n                                      np.expm1(np.maximum(y_pred_log, 0))))\n\ndef mae_original(y_true_log, y_pred_log):\n    return mean_absolute_error(np.expm1(y_true_log), \n                               np.expm1(np.maximum(y_pred_log, 0)))\n\ndef r2_original(y_true_log, y_pred_log):\n    return r2_score(np.expm1(y_true_log), \n                    np.expm1(np.maximum(y_pred_log, 0)))\n\ndef mape(y_true_log, y_pred_log):\n    y_true = np.expm1(np.array(y_true_log))\n    y_pred = np.expm1(np.maximum(np.array(y_pred_log), 0))\n    mask = y_true > 0\n    return np.mean(np.abs((y_true[mask] - y_pred[mask]) / y_true[mask])) * 100\n\n# ============================================================================\n# 1. LIGHTGBM\n# ============================================================================\nprint("\\n" + "="*60)\nprint("Training LightGBM...")\nprint("="*60)\n\ntry:\n    import lightgbm as lgb\n    \n    lgb_model = lgb.LGBMRegressor(\n        n_estimators=500,\n        learning_rate=0.05,\n        num_leaves=63,\n        colsample_bytree=0.8,\n        subsample=0.8,\n        random_state=42,\n        verbose=-1,\n        n_jobs=-1\n    )\n    lgb_model.fit(\n        X_train, y_train,\n        eval_set=[(X_test, y_test)],\n        eval_metric=\'rmse\',\n        callbacks=[lgb.early_stopping(stopping_rounds=50)]\n    )\n    \n    lgb_pred = lgb_model.predict(X_test)\n    lgb_rmse  = rmse_original(y_test, lgb_pred)\n    lgb_mae   = mae_original(y_test, lgb_pred)\n    lgb_mape  = mape(y_test, lgb_pred)\n    lgb_r2    = r2_original(y_test, lgb_pred)\n    \n    print(f"{\'=\'*50}")\n    print(f"LightGBM Results")\n    print(f"{\'=\'*50}")\n    print(f"  RMSE : {lgb_rmse:.4f}")\n    print(f"  MAE  : {lgb_mae:.4f}")\n    print(f"  MAPE : {lgb_mape:.2f}%")\n    print(f"  R²   : {lgb_r2:.4f}")\n    \n    with open(\'trained_models/lgb_model.pkl\', \'wb\') as f:\n        pickle.dump(lgb_model, f)\n    print("✓ LightGBM saved")\nexcept Exception as e:\n    print(f"✗ LightGBM failed: {e}")\n\n# ============================================================================\n# 2. XGBOOST\n# ============================================================================\nprint("\\n" + "="*60)\nprint("Training XGBoost...")\nprint("="*60)\n\ntry:\n    from xgboost import XGBRegressor\n    \n    xgb_model = XGBRegressor(\n        n_estimators=500,\n        learning_rate=0.05,\n        max_depth=6,\n        subsample=0.8,\n        colsample_bytree=0.8,\n        random_state=42,\n        n_jobs=-1,\n        early_stopping_rounds=50,\n        eval_metric=\'rmse\',\n        verbosity=0\n    )\n    xgb_model.fit(\n        X_train, y_train,\n        eval_set=[(X_test, y_test)],\n        verbose=False\n    )\n    \n    xgb_pred = xgb_model.predict(X_test)\n    xgb_rmse  = rmse_original(y_test, xgb_pred)\n    xgb_mae   = mae_original(y_test, xgb_pred)\n    xgb_mape  = mape(y_test, xgb_pred)\n    xgb_r2    = r2_original(y_test, xgb_pred)\n    \n    print(f"{\'=\'*50}")\n    print(f"XGBoost Results")\n    print(f"{\'=\'*50}")\n    print(f"  RMSE : {xgb_rmse:.4f}")\n    print(f"  MAE  : {xgb_mae:.4f}")\n    print(f"  MAPE : {xgb_mape:.2f}%")\n    print(f"  R²   : {xgb_r2:.4f}")\n    \n    with open(\'trained_models/xgb_model.pkl\', \'wb\') as f:\n        pickle.dump(xgb_model, f)\n    print("✓ XGBoost saved")\nexcept Exception as e:\n    print(f"✗ XGBoost failed: {e}")\n\n# ============================================================================\n# 3. PROPHET\n# ============================================================================\nprint("\\n" + "="*60)\nprint("Training Prophet...")\nprint("="*60)\n\ntry:\n    from prophet import Prophet\n    \n    # Load raw data\n    train_raw = pd.read_parquet("preprocessed_data/train_raw.parquet")\n    test_raw  = pd.read_parquet("preprocessed_data/test_raw.parquet")\n    \n    # Aggregate to daily\n    prophet_train = train_raw.groupby(\'date\')[\'quantity\'].sum().reset_index()\n    prophet_train.columns = [\'ds\', \'y\']\n    \n    prophet_test = test_raw.groupby(\'date\')[\'quantity\'].sum().reset_index()\n    prophet_test.columns = [\'ds\', \'y\']\n    \n    # Train\n    prophet_model = Prophet(\n        yearly_seasonality=True,\n        weekly_seasonality=True,\n        daily_seasonality=False,\n        seasonality_mode=\'multiplicative\',\n        interval_width=0.90\n    )\n    prophet_model.add_country_holidays(country_name=\'RU\')\n    \n    with warnings.catch_warnings():\n        warnings.simplefilter("ignore")\n        prophet_model.fit(prophet_train)\n    \n    # Predict\n    future   = prophet_model.make_future_dataframe(periods=len(prophet_test))\n    \n    with warnings.catch_warnings():\n        warnings.simplefilter("ignore")\n        forecast = prophet_model.predict(future)\n    \n    prophet_pred   = forecast.tail(len(prophet_test))[\'yhat\'].clip(lower=0).values\n    prophet_actual = prophet_test[\'y\'].values\n    \n    # Evaluate\n    prophet_rmse = np.sqrt(mean_squared_error(prophet_actual, prophet_pred))\n    prophet_mae  = mean_absolute_error(prophet_actual, prophet_pred)\n    mask = prophet_actual > 0\n    prophet_mape = np.mean(np.abs((prophet_actual[mask] - prophet_pred[mask]) \n                                   / prophet_actual[mask])) * 100\n    \n    print(f"{\'=\'*50}")\n    print(f"Prophet Results")\n    print(f"{\'=\'*50}")\n    print(f"  RMSE : {prophet_rmse:.4f}")\n    print(f"  MAE  : {prophet_mae:.4f}")\n    print(f"  MAPE : {prophet_mape:.2f}%")\n    print(f"  R²   : N/A (aggregated series)")\n    \n    with open(\'trained_models/prophet_model.pkl\', \'wb\') as f:\n        pickle.dump(prophet_model, f)\n    print("✓ Prophet saved")\nexcept Exception as e:\n    print(f"✗ Prophet failed: {e}")\n\n# ============================================================================\n# SUMMARY\n# ============================================================================\nprint("\\n" + "="*60)\nprint("MODEL COMPARISON SUMMARY")\nprint("="*60)\n\ntry:\n    print("\\n✓ LightGBM:  RMSE={:.4f}, MAE={:.4f}, MAPE={:.2f}%, R²={:.4f}".format(\n        lgb_rmse, lgb_mae, lgb_mape, lgb_r2))\nexcept:\n    print("✗ LightGBM: Training failed")\n\ntry:\n    print("✓ XGBoost:   RMSE={:.4f}, MAE={:.4f}, MAPE={:.2f}%, R²={:.4f}".format(\n        xgb_rmse, xgb_mae, xgb_mape, xgb_r2))\nexcept:\n    print("✗ XGBoost: Training failed")\n\ntry:\n    print("✓ Prophet:   RMSE={:.4f}, MAE={:.4f}, MAPE={:.2f}%".format(\n        prophet_rmse, prophet_mae, prophet_mape))\nexcept:\n    print("✗ Prophet: Training failed")\n\nprint("\\n✓ All models trained and saved!")\n')
