    f_out.write('#!/usr/bin/env python3\n"""Quick training with progress logging"""\n\nimport os\nimport sys\nimport pickle\nimport numpy as np\nimport pandas as pd\nimport warnings\n\n# Redirect output to both console and log file\nlog_file = "training_log.txt"\nclass Logger:\n    def __init__(self):\n        self.terminal = sys.stdout\n        self.log = open(log_file, \'w\')\n    \n    def write(self, message):\n        self.terminal.write(message)\n        self.log.write(message)\n        self.log.flush()\n    \n    def flush(self):\n        pass\n\nsys.stdout = Logger()\n\nwarnings.filterwarnings(\'ignore\')\nfrom sklearn.metrics import mean_squared_error, mean_absolute_error, r2_score\n\nprint("="*70)\nprint("QUICK MODEL TRAINING (20% Sample)")\nprint("="*70)\n\ntry:\n    print("\\n[1/4] Loading data...")\n    data_dir = "preprocessed_data"\n    X_train_full = pd.read_parquet(f"{data_dir}/X_train.parquet")\n    X_test_full = pd.read_parquet(f"{data_dir}/X_test.parquet")\n    y_train_full = pd.read_parquet(f"{data_dir}/y_train.parquet").iloc[:, 0]\n    y_test_full = pd.read_parquet(f"{data_dir}/y_test.parquet").iloc[:, 0]\n    print("✓ Data loaded")\n    \n    # Sample 20%\n    print("\\n[2/4] Sampling 20% for speed...")\n    np.random.seed(42)\n    train_idx = np.random.choice(len(X_train_full), size=int(0.2*len(X_train_full)), replace=False)\n    test_idx = np.random.choice(len(X_test_full), size=int(0.2*len(X_test_full)), replace=False)\n    \n    X_train = X_train_full.iloc[train_idx].reset_index(drop=True)\n    X_test = X_test_full.iloc[test_idx].reset_index(drop=True)\n    y_train = y_train_full.iloc[train_idx].reset_index(drop=True)\n    y_test = y_test_full.iloc[test_idx].reset_index(drop=True)\n    print(f"✓ X_train: {X_train.shape}, X_test: {X_test.shape}")\n    \n    # Metrics\n    def rmse_original(y_true_log, y_pred_log):\n        return np.sqrt(mean_squared_error(np.expm1(y_true_log),\n                                          np.expm1(np.maximum(y_pred_log, 0))))\n    \n    def mae_original(y_true_log, y_pred_log):\n        return mean_absolute_error(np.expm1(y_true_log), \n                                   np.expm1(np.maximum(y_pred_log, 0)))\n    \n    def r2_original(y_true_log, y_pred_log):\n        return r2_score(np.expm1(y_true_log), \n                        np.expm1(np.maximum(y_pred_log, 0)))\n    \n    def mape(y_true_log, y_pred_log):\n        y_true = np.expm1(np.array(y_true_log))\n        y_pred = np.expm1(np.maximum(np.array(y_pred_log), 0))\n        mask = y_true > 0\n        return np.mean(np.abs((y_true[mask] - y_pred[mask]) / y_true[mask])) * 100\n    \n    results = {}\n    \n    # ============================================================================\n    # 1. LIGHTGBM\n    # ============================================================================\n    print("\\n[3/4] Training LightGBM...")\n    import lightgbm as lgb\n    \n    lgb_model = lgb.LGBMRegressor(\n        n_estimators=200, learning_rate=0.1, num_leaves=32,\n        subsample=0.8, colsample_bytree=0.8, random_state=42,\n        verbose=-1, n_jobs=-1\n    )\n    lgb_model.fit(X_train, y_train, eval_set=[(X_test, y_test)],\n                  eval_metric=\'rmse\', callbacks=[lgb.early_stopping(20)])\n    \n    lgb_pred = lgb_model.predict(X_test)\n    lgb_rmse  = rmse_original(y_test, lgb_pred)\n    lgb_mae   = mae_original(y_test, lgb_pred)\n    lgb_mape  = mape(y_test, lgb_pred)\n    lgb_r2    = r2_original(y_test, lgb_pred)\n    results[\'LightGBM\'] = {\'rmse\': lgb_rmse, \'mae\': lgb_mae, \'mape\': lgb_mape, \'r2\': lgb_r2}\n    print(f"✓ LightGBM: RMSE={lgb_rmse:.4f}, MAE={lgb_mae:.4f}, MAPE={lgb_mape:.2f}%, R²={lgb_r2:.4f}")\n    \n    # ============================================================================\n    # 2. XGBOOST\n    # ============================================================================\n    print("\\n[4/4] Training XGBoost...")\n    from xgboost import XGBRegressor\n    \n    xgb_model = XGBRegressor(\n        n_estimators=200, learning_rate=0.1, max_depth=4,\n        subsample=0.8, colsample_bytree=0.8, random_state=42,\n        n_jobs=-1, early_stopping_rounds=20, eval_metric=\'rmse\', verbosity=0\n    )\n    xgb_model.fit(X_train, y_train, eval_set=[(X_test, y_test)], verbose=False)\n    \n    xgb_pred = xgb_model.predict(X_test)\n    xgb_rmse  = rmse_original(y_test, xgb_pred)\n    xgb_mae   = mae_original(y_test, xgb_pred)\n    xgb_mape  = mape(y_test, xgb_pred)\n    xgb_r2    = r2_original(y_test, xgb_pred)\n    results[\'XGBoost\'] = {\'rmse\': xgb_rmse, \'mae\': xgb_mae, \'mape\': xgb_mape, \'r2\': xgb_r2}\n    print(f"✓ XGBoost: RMSE={xgb_rmse:.4f}, MAE={xgb_mae:.4f}, MAPE={xgb_mape:.2f}%, R²={xgb_r2:.4f}")\n    \n    # ============================================================================\n    # SUMMARY\n    # ============================================================================\n    print("\\n" + "="*70)\n    print("MODEL COMPARISON (20% Sample)")\n    print("="*70)\n    print(f"\\n{\'Model\':<15} {\'RMSE\':<12} {\'MAE\':<12} {\'MAPE %\':<12} {\'R²\':<12}")\n    print("-" * 70)\n    \n    for model_name, metrics in sorted(results.items()):\n        print(f"{model_name:<15} {metrics[\'rmse\']:<12.4f} {metrics[\'mae\']:<12.4f} "\n              f"{metrics[\'mape\']:<12.2f} {metrics[\'r2\']:<12.4f}")\n    \n    best = min(results.items(), key=lambda x: x[1][\'rmse\'])\n    print("-" * 70)\n    print(f"\\n🏆 Best Model: {best[0]} (RMSE: {best[1][\'rmse\']:.4f})")\n    print(f"📊 Baseline (Mean): 27.80")\n    print(f"   Improvement: {((27.80 - best[1][\'rmse\']) / 27.80 * 100):.1f}%")\n    print("\\n✓ Complete!")\n\nexcept Exception as e:\n    print(f"\\n✗ Error: {e}")\n    import traceback\n    traceback.print_exc()\n')
