    f_out.write('\n# ============== STEP 3: Real Dashboard Data ==============\n\n"""\nReplace /api/dashboard-data with:\n\n@app.route(\'/api/dashboard-data\', methods=[\'GET\'])\ndef get_dashboard_data():\n    try:\n        # Load from database or CSV\n        df = pd.read_csv(\'data/sales_history.csv\')\n        \n        # Calculate KPIs\n        total_revenue = df[\'sales\'].sum()\n        avg_daily_sales = df.groupby(\'date\')[\'sales\'].sum().mean()\n        \n        # Get recent predictions vs actual\n        predictions = pd.read_csv(\'data/predictions.csv\')\n        accuracy = calculate_rmse(predictions[\'actual\'], predictions[\'predicted\'])\n        \n        # Daily trend (last 30 days)\n        daily_data = df.tail(30).groupby(\'date\')[\'sales\'].sum()\n        daily_sales_trend = [\n            {"date": date, "sales": float(sales)}\n            for date, sales in daily_data.items()\n        ]\n        \n        # Top items (by demand)\n        top_items = df.groupby([\'item_id\', \'item_name\'])[\'quantity\'].sum().nlargest(3)\n        top_items_list = [\n            {"item_id": item_id, "name": item_name, "demand": int(quantity)}\n            for (item_id, item_name), quantity in top_items.items()\n        ]\n        \n        return jsonify({\n            "kpis": {\n                "total_revenue": float(total_revenue),\n                "avg_daily_sales": float(avg_daily_sales),\n                "prediction_accuracy": 0.89,  # Calculate from predictions\n                "forecast_models": 4\n            },\n            "daily_sales_trend": daily_sales_trend,\n            "top_items": top_items_list\n        })\n    \n    except Exception as e:\n        return jsonify({"error": str(e)}), 500\n"""\n\n# ============== STEP 4: Real Model Metrics ==============\n')
