    f_out.write('"""\n\n# ============== REQUIRED HELPER FUNCTIONS ==============\n\ndef prepare_input_features(raw_input):\n    """\n    Convert raw input to feature vector matching training data\n    Must match exactly the features used during model training\n    """\n    from datetime import datetime\n    \n    # Parse date\n    date_obj = datetime.strptime(raw_input[\'date\'], \'%Y-%m-%d\')\n    \n    # Create features in SAME ORDER as training\n    features = [\n        raw_input[\'store_id\'],\n        raw_input[\'item_id\'],\n        raw_input[\'price\'],\n        raw_input[\'discount\'],\n        date_obj.dayofweek,  # 0-6 (Monday-Sunday)\n        date_obj.month,\n        date_obj.dayofyear,\n        1 if raw_input[\'channel\'] == \'online\' else 0,  # One-hot encode\n        # Add any other engineered features that were in training data\n    ]\n    \n    return features\n\n\ndef calculate_rmse(actual, predicted):\n    """Calculate RMSE between actual and predicted"""\n    import numpy as np\n    return np.sqrt(np.mean((actual - predicted) ** 2))\n\n\n# ============== FILE STRUCTURE NEEDED ==============\n\n"""\nOnce you have real models, organize files like:\n\ndemand_forecasting_app/\n├── models/\n│   ├── lightgbm_model.pkl          # Trained LightGBM model\n│   ├── feature_scaler.pkl          # StandardScaler for features\n│   ├── feature_names.pkl           # List of feature names\n│   ├── xgboost_model.pkl           # Other models\n│   └── sarima_model.pkl\n├── data/\n│   ├── sales_history.csv           # Historical sales data\n')
