with open(dest_path, 'a', encoding='utf-8') as f_out:
    f_out.write('import pandas as pd\nimport numpy as np\n\ndef preprocess_prediction_input(data):\n    """\n    Transforms raw input from the web form into a feature vector \n    compatible with the LightGBM model.\n    """\n    # Example feature engineering from the notebooks\n    features = {\n        \'store_id\': data.get(\'store_id\'),\n        \'item_id\': data.get(\'item_id\'),\n        \'price\': data.get(\'price\'),\n        \'discount\': data.get(\'discount\'),\n        \'channel\': 1 if data.get(\'channel\') == \'online\' else 0,\n    }\n    \n    # Extract date features\n    date = pd.to_datetime(data.get(\'date\'))\n    features[\'day_of_week\'] = date.dayofweek\n    features[\'month\'] = date.month\n    features[\'is_weekend\'] = 1 if date.dayofweek >= 5 else 0\n    \n    # Convert to DataFrame for model inference\n    return pd.DataFrame([features])\n\n')
